SELECT TDS.ID TDS_ID, TDS.SCN TDS_SCN, TDS.SHIP_ID TDS_SHIP_ID, TDS.SHIP_NAME TDS_SHIP_NAME, TS.SHIP_NAME_EN TS_SHIP_NAME_EN, TDS.IMP_EXP TDS_IMP_EXP, TDS.TRADE_TYPE TDS_TRADE_TYPE, TDS.LOAD_UNLOAD TDS_LOAD_UNLOAD, TDS.IS_WATER TDS_IS_WATER, TDS.IS_SHORE_POWER TDS_IS_SHORE_POWER, TDS.REQ_WATER TDS_REQ_WATER, TDS.REQ_ELECTRICITY TDS_REQ_ELECTRICITY, TDS.BOW_DRAFT TDS_BOW_DRAFT, TDS.STERN_DRAFT TDS_STERN_DRAFT, TDS.IS_TUG TDS_IS_TUG, TDS.TUG_NUMBER TDS_TUG_NUMBER, TDS.PILOTAGE TDS_PILOTAGE, TDS.IS_PAYMENT TDS_IS_PAYMENT, TDS.PAYMENT_AMOUNT TDS_PAYMENT_AMOUNT, TDS.IS_DANGEROUS TDS_IS_DANGEROUS, TDS.ARRIVAL_TIME_PLAN TDS_ARRIVAL_TIME_PLAN, TDS.LEAVE_PORT_TIME_PLAN TDS_LEAVE_PORT_TIME_PLAN, TDS.LEAVE_PORT_TIME TDS_LEAVE_PORT_TIME, TDS.ARRIVAL_ANCHORAGE_TIME TDS_ARRIVAL_ANCHORAGE_TIME, TDS.LEAVE_ANCHORAGE_TIME TDS_LEAVE_ANCHORAGE_TIME, TDS.BERTH_TIME TDS_BERTH_TIME, TDS.BERTH_ID TDS_BERTH_ID, TDS.BERTH_NAME TDS_BERTH_NO, TDS.BERTH_TYPE TDS_BERTH_TYPE, TDS.BOLLARD_NO_START TDS_BOLLARD_NO_START, TDS.BOLLARD_NO_END TDS_BOLLARD_NO_END, TDS.LEAVE_BERTH_TIME TDS_LEAVE_BERTH_TIME, TDS.RECEIVE_BY TDS_RECEIVE_BY, TDS.RECEIVE_BY_NAME TDS_RECEIVE_BY_NAME, TDS.RECEIVE_TIME TDS_RECEIVE_TIME, TDS.DEL_FLAG TDS_DEL_FLAG, TDS.DEL_REMARK TDS_DEL_REMARK, TDS.DEL_BY TDS_DEL_BY, TDS.DEL_BY_NAME TDS_DEL_BY_NAME, TDS.DEL_TIME TDS_DEL_TIME, TDS.REMARK TDS_REMARK, TDS.CREATE_BY TDS_CREATE_BY, TDS.CREATE_BY_NAME TDS_CREATE_BY_NAME, TDS.CREATE_TIME TDS_CREATE_TIME, TDS.UPDATE_BY TDS_UPDATE_BY, TDS.UPDATE_BY_NAME TDS_UPDATE_BY_NAME, TDS.UPDATE_TIME TDS_UPDATE_TIME, TDS.START_PORT_ID TDS_START_PORT_ID, TDS.START_PORT_NAME TDS_START_PORT_NAME, TDS.END_PORT_ID TDS_END_PORT_ID, TDS.END_PORT_NAME TDS_END_PORT_NAME, TDS.PRE_PORT_ID TDS_PRE_PORT_ID, TDS.PRE_PORT_NAME TDS_PRE_PORT_NAME, TDS.NEXT_PORT_ID TDS_NEXT_PORT_ID, TDS.NEXT_PORT_NAME TDS_NEXT_PORT_NAME, TDS.SHIP_STATUS_CODE TDS_SHIP_STATUS_CODE, TDS.SHIP_STATUS_NAME TDS_SHIP_STATUS_NAME, TDS.CERTIFICATE_PATH TDS_CERTIFICATE_PATH, TDS.IS_START_WORK TDS_IS_START_WORK, TDS.IS_LAST_ARRIVAL_TYPE TDS_IS_LAST_ARRIVAL_TYPE, TDS.BERTHING_CHARGE TDS_BERTHING_CHARGE, TDS.JIESHOU_REMARK TDS_JIESHOU_REMARK, TS.CAPTAIN_PHONE TS_CAPTAIN_PHONE, TDS.WHARF TDS_WHARF, TS.HATCH_NUM SHIP_HATCH_NUM, TS.IS_FOCUS_SHIP IS_FOCUS_SHIP, TDS.CONFIRM_TIME TDS_CONFIRM_TIME, "IN".ID IN_ID, "IN".SHIPVOYAGE_ID IN_SHIPVOYAGE_ID, "IN".IMP_EXP IN_IMP_EXP, "IN".TRADE_TYPE IN_TRADE_TYPE, "IN".LOAD_UNLOAD IN_LOAD_UNLOAD, "IN".VOYAGE IN_VOYAGE, "IN".COMPANY_ID IN_COMPANY_ID, "IN".COMPANY_NAME IN_COMPANY_NAME, "IN".CARGO_CATEGORY_CODE IN_CARGO_CATEGORY_CODE, "IN".CARGO_CATEGORY_NAME IN_CARGO_CATEGORY_NAME, "IN".CARGO_NUM IN_CARGO_NUM, "IN".CUSTOMER_ID IN_CUSTOMER_ID, "IN".CUSTOMER_NAME IN_CUSTOMER_NAME, "IN".CONTACTS IN_CONTACTS, "IN".SHIP_PHONE IN_SHIP_PHONE, "IN".PAYMENT_AMOUNT IN_PAYMENT_AMOUNT, "IN".REMARK IN_REMARK, "IN".CREATE_BY IN_CREATE_BY, "IN".CREATE_BY_NAME IN_CREATE_BY_NAME, "IN".CREATE_TIME IN_CREATE_TIME, "IN".UPDATE_BY IN_UPDATE_BY, "IN".UPDATE_BY_NAME IN_UPDATE_BY_NAME, "IN".UPDATE_TIME IN_UPDATE_TIME, "IN".SHIP_STATUS_CODE IN_SHIP_STATUS_CODE, "IN".SHIP_STATUS_NAME IN_SHIP_STATUS_NAME, "IN".WORK_START_TIME IN_WORK_START_TIME, "IN".WORK_END_TIME IN_WORK_END_TIME, "IN".PRE_CHANGE_SHIP_NAME IN_PRE_CHANGE_SHIP_NAME, "IN".PRE_CHANGE_SHIP_NO IN_PRE_CHANGE_SHIP_NO, "IN".FIR_CARGO_CATE IN_FIR_CARGO_CATE, "IN".SEC_CARGO_CATE IN_SEC_CARGO_CATE, "OUT".ID OUT_ID, "OUT".SHIPVOYAGE_ID OUT_SHIPVOYAGE_ID, "OUT".IMP_EXP OUT_IMP_EXP, "OUT".TRADE_TYPE OUT_TRADE_TYPE, "OUT".LOAD_UNLOAD OUT_LOAD_UNLOAD, "OUT".VOYAGE OUT_VOYAGE, "OUT".COMPANY_ID OUT_COMPANY_ID, "OUT".COMPANY_NAME OUT_COMPANY_NAME, "OUT".CARGO_CATEGORY_CODE OUT_CARGO_CATEGORY_CODE, "OUT".CARGO_CATEGORY_NAME OUT_CARGO_CATEGORY_NAME, "OUT".CARGO_NUM OUT_CARGO_NUM, "OUT".CUSTOMER_ID OUT_CUSTOMER_ID, "OUT".CUSTOMER_NAME OUT_CUSTOMER_NAME, "OUT".CONTACTS OUT_CONTACTS, "OUT".SHIP_PHONE OUT_SHIP_PHONE, "OUT".PAYMENT_AMOUNT OUT_PAYMENT_AMOUNT, "OUT".REMARK OUT_REMARK, "OUT".CREATE_BY OUT_CREATE_BY, "OUT".CREATE_BY_NAME OUT_CREATE_BY_NAME, "OUT".CREATE_TIME OUT_CREATE_TIME, "OUT".UPDATE_BY OUT_UPDATE_BY, "OUT".UPDATE_BY_NAME OUT_UPDATE_BY_NAME, "OUT".UPDATE_TIME OUT_UPDATE_TIME, "OUT".SHIP_STATUS_CODE OUT_SHIP_STATUS_CODE, "OUT".SHIP_STATUS_NAME OUT_SHIP_STATUS_NAME, "OUT".WORK_START_TIME OUT_WORK_START_TIME, "OUT".WORK_END_TIME OUT_WORK_END_TIME, "OUT".FIR_CARGO_CATE OUT_FIR_CARGO_CATE, "OUT".SEC_CARGO_CATE OUT_SEC_CARGO_CATE FROM T_DIS_SHIPVOYAGE TDS LEFT JOIN T_DIS_SHIPVOYAGE_ITEM "IN" ON ("IN".IMP_EXP = 'IN' AND TDS.ID = "IN".SHIPVOYAGE_ID) LEFT JOIN T_DIS_SHIPVOYAGE_ITEM "OUT" ON ("OUT".IMP_EXP = 'OUT' AND TDS.ID = "OUT".SHIPVOYAGE_ID) LEFT JOIN M_SHIP TS ON TS.ID = TDS.SHIP_ID
TDS.SHIP_STATUS_CODE IN ( '11', '10', '20','30','50','60', '70','80','90','100','110')
AND TS.SHIP_KIND_CODE = #{shipKindCode,jdbcType=VARCHAR}
and TDS.ID = #{id, jdbcType=BIGINT}
and TDS.SCN = #{scn, jdbcType=VARCHAR}
and TDS.SHIP_ID = #{shipId, jdbcType=BIGINT}
AND (TDS.SHIP_NAME LIKE #{shipName,jdbcType=VARCHAR})
AND ("IN".VOYAGE LIKE #{voyage,jdbcType=VARCHAR} OR "OUT".VOYAGE LIKE #{voyage,jdbcType=VARCHAR})
and TDS.IMP_EXP = #{impExp, jdbcType=VARCHAR}
and TDS.TRADE_TYPE = #{tradeType, jdbcType=VARCHAR}
and TDS.LOAD_UNLOAD = #{loadUnload, jdbcType=VARCHAR}
and TDS.IS_WATER = #{isWater, jdbcType=VARCHAR}
and TDS.IS_SHORE_POWER = #{isShorePower, jdbcType=VARCHAR}
and TDS.REQ_WATER = #{reqWater, jdbcType=VARCHAR}
and TDS.REQ_ELECTRICITY = #{reqElectricity, jdbcType=VARCHAR}
and TDS.BOW_DRAFT = #{bowDraft, jdbcType=VARCHAR}
and TDS.STERN_DRAFT = #{sternDraft, jdbcType=VARCHAR}
and TDS.IS_TUG = #{isTug, jdbcType=VARCHAR}
and TDS.TUG_NUMBER = #{tugNumber, jdbcType=INTEGER}
and TDS.PILOTAGE = #{pilotage, jdbcType=VARCHAR}
and TDS.IS_PAYMENT = #{isPayment, jdbcType=VARCHAR}
and TDS.PAYMENT_AMOUNT = #{paymentAmount, jdbcType=VARCHAR}
and TDS.IS_DANGEROUS = #{isDangerous, jdbcType=VARCHAR}
and TDS.ARRIVAL_TIME_PLAN = #{arrivalTimePlan, jdbcType=TIMESTAMP}
and TDS.LEAVE_PORT_TIME_PLAN = #{leavePortTimePlan, jdbcType=TIMESTAMP}
AND TDS.LEAVE_PORT_TIME >= #{startLeaveTime, jdbcType=VARCHAR}
AND #{endLeaveTime, jdbcType=VARCHAR} >= TDS.LEAVE_PORT_TIME
and TDS.ARRIVAL_ANCHORAGE_TIME = #{arrivalAnchorageTime, jdbcType=TIMESTAMP}
and TDS.LEAVE_ANCHORAGE_TIME = #{leaveAnchorageTime, jdbcType=TIMESTAMP}
and TDS.BERTH_TIME = #{berthTime, jdbcType=TIMESTAMP}
and TDS.BERTH_ID = #{berthId, jdbcType=BIGINT}
and TDS.BERTH_NAME = #{berthName, jdbcType=VARCHAR}
and TDS.BERTH_TYPE = #{berthType, jdbcType=VARCHAR}
and TDS.BOLLARD_NO_START = #{bollardNoStart, jdbcType=VARCHAR}
and TDS.BOLLARD_NO_END = #{bollardNoEnd, jdbcType=VARCHAR}
and TDS.LEAVE_BERTH_TIME = #{leaveBerthTime, jdbcType=TIMESTAMP}
and TDS.RECEIVE_BY = #{receiveBy, jdbcType=BIGINT}
and TDS.RECEIVE_BY_NAME = #{receiveByName, jdbcType=VARCHAR}
and TDS.RECEIVE_TIME = #{receiveTime, jdbcType=TIMESTAMP}
and TDS.DEL_FLAG = #{delFlag,jdbcType=VARCHAR}
and TDS.DEL_REMARK = #{delRemark, jdbcType=VARCHAR}
and TDS.DEL_BY = #{delBy, jdbcType=BIGINT}
and TDS.DEL_BY_NAME = #{delByName, jdbcType=VARCHAR}
and TDS.DEL_TIME = #{delTime, jdbcType=TIMESTAMP}
and TDS.REMARK = #{remark, jdbcType=VARCHAR}
and TDS.CREATE_BY = #{createBy, jdbcType=BIGINT}
and TDS.CREATE_BY_NAME = #{createByName, jdbcType=VARCHAR}
and TDS.CREATE_TIME = #{createTime, jdbcType=TIMESTAMP}
and TDS.UPDATE_BY = #{updateBy, jdbcType=BIGINT}
and TDS.UPDATE_BY_NAME = #{updateByName, jdbcType=VARCHAR}
and TDS.UPDATE_TIME = #{updateTime, jdbcType=TIMESTAMP}
and TDS.START_PORT_ID = #{startPortId, jdbcType=BIGINT}
and TDS.START_PORT_NAME = #{startPortName, jdbcType=VARCHAR}
and TDS.END_PORT_ID = #{endPortId, jdbcType=BIGINT}
and TDS.END_PORT_NAME = #{endPortName, jdbcType=VARCHAR}
and TDS.PRE_PORT_ID = #{prePortId, jdbcType=BIGINT}
and TDS.PRE_PORT_NAME = #{prePortName, jdbcType=VARCHAR}
and TDS.NEXT_PORT_ID = #{nextPortId, jdbcType=BIGINT}
and TDS.NEXT_PORT_NAME = #{nextPortName, jdbcType=VARCHAR}
and TDS.SHIP_STATUS_CODE = #{shipStatusCode, jdbcType=VARCHAR}
and TDS.SHIP_STATUS_NAME = #{shipStatusName, jdbcType=VARCHAR}
and ("IN".ID = #{shipVoyage, jdbcType=VARCHAR} OR "OUT".ID = #{shipVoyage, jdbcType=VARCHAR})
AND ("IN".CARGO_CATEGORY_NAME LIKE #{cargoCategoryName,jdbcType=VARCHAR} OR "OUT".CARGO_CATEGORY_NAME LIKE #{cargoCategoryName,jdbcType=VARCHAR})
ORDER BY TDS.CREATE_TIME DESC

mapper.select:
select *
from T_DIS_SHIPVOYAGE_ITEM
where ID = #{id, jdbcType=BIGINT}

select *
from T_DIS_SHIPVOYAGE_ITEM
where SHIPVOYAGE_ID = #{shipvoyageId, jdbcType=BIGINT}

SELECT SUM(A.TON) "ton" FROM T_BUS_HANDOVERLIST A LEFT JOIN T_DIS_SHIPVOYAGE B ON A.SHIPVOYAGE_ID = B.ID LEFT JOIN T_DIS_SHIP_DYNAMIC C ON C.SHIPVOYAGE_ID = B.ID LEFT JOIN M_CARGO D ON D.CARGO_NAME = A.CARGO_NAME WHERE A.TYPE = '1' AND B.SHIP_STATUS_CODE = '120' AND B.LEAVE_PORT_TIME >= #{startTime} AND #{endTime} >= B.LEAVE_PORT_TIME
AND A.CARGO_NAME LIKE #{cargoNameLike}
AND D.WORK_TYPE = #{workType}

SELECT '港口作业包干费' "name", NVL(SUM("value"),0) "value" FROM ( SELECT '包干费' "name", SUM(TCSD.AMOUNT) "value" FROM T_COST_STATEMENT TCS LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TCS.ID = TCSD.STATEMENT WHERE TCS.TYPE = '10' OR TCS.TYPE = '20' AND TCS.CREATE_TIME >= #{startTime} AND #{endTime} >= TCS.CREATE_TIME
AND TCS.CARGO_NAME LIKE #{cargoNameLike}
UNION ALL SELECT '港口作业包干费' "name", NVL(SUM(TCSD.AMOUNT),0) "value" FROM T_COST_STATEMENT TCS LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TCS.ID = TCSD.STATEMENT LEFT JOIN T_BUS_RATE TBR ON TCSD.RATE_ID = TBR.ID WHERE TCS.TYPE = '40' AND TBR.RATE_ITEM_NAME LIKE '港口作业包干费%' AND TCS.CREATE_TIME >= #{startTime} AND #{endTime} >= TCS.CREATE_TIME
AND TCS.CARGO_NAME LIKE #{cargoNameLike}
) UNION ALL SELECT '停泊费' "name", NVL(SUM(TCSD.AMOUNT),0) "value" FROM T_COST_STATEMENT TCS LEFT JOIN T_COST_STATEMENT_DETAIL TCSD ON TCS.ID = TCSD.STATEMENT LEFT JOIN T_COST_SHIP TCSHIP ON TCSHIP.ID = TCSD.BUSINESS_ID WHERE TCS.TYPE = '30' and TCSHIP.TYPE = '10' AND TCS.CREATE_TIME >= #{startTime} AND #{endTime} >= TCS.CREATE_TIME
AND TCS.CARGO_NAME LIKE #{cargoNameLike}

SELECT TO_CHAR(WORK_DATE, 'MM.DD') "name", NVL(SUM(AMOUNT),0) "value" FROM ( SELECT TPS.SHIP_VOYAGE, TPS.WORK_DATE, TPS.SHIP_VOYAGE_ITEM_ID, TPS.PRICE, TPS.TON, TPS.AMOUNT, TPS.SALARY_TYPE_CODE FROM T_PRD_SALARY TPS LEFT JOIN T_PRD_WORK_TICKET_DETAIL TPWTD ON TPWTD.ID = TPS.WORK_TICKET_DETAIL_ID LEFT JOIN T_PRD_WORK_TICKET TPWT ON TPWT.ID = TPS.WORK_TICKET_ID WHERE TPS.WORK_DATE >= to_date(to_char(#{startTime}, 'YYYY-MM-DD hh24:mi:ss'), 'YYYY-MM-DD hh24:mi:ss') AND to_date(to_char(#{endTime}, 'YYYY-MM-DD hh24:mi:ss'), 'YYYY-MM-DD hh24:mi:ss') >= TPS.WORK_DATE AND TPS.SALARY_STATUS_CODE = '20'
AND TPS.CARGO_NAME LIKE #{cargoNameLike}
ORDER BY TPS.WORK_DATE ASC, TPS.DEPT_NAME ASC, TPS.CLASS_NAME ASC, TPS.USER_BY_NAME ) GROUP BY WORK_DATE ORDER BY "name"

SELECT A.COMPANY_ID,A.CUSTOMER_ID,ROUND((nvl(A.CUSTOMER_AMOUNT,0)-nvl(B.PAYMENT_SUM,0)-nvl(C.INVOICE_AMOUNT,0)),2) "amount" FROM ( select CUSTOMER_ID,COMPANY_ID,SUM(PREPAYMENT_AMOUNT-UTILIZED_AMOUNT) CUSTOMER_AMOUNT FROM T_FD_BANK_CUSTOMER_PREPAYMENT WHERE STATUS = 1 AND PREPAYMENT_TYPE_CODE = 30 GROUP BY CUSTOMER_ID,COMPANY_ID ) A LEFT JOIN ( select t1.CUSTOMER_ID CUSTOMER_ID,t1.COMPANY_ID COMPANY_ID,SUM(t1.PAYMENT_AMOUNT) PAYMENT_SUM FROM T_DIS_SHIPVOYAGE t LEFT JOIN T_DIS_SHIPVOYAGE_ITEM t1 ON t.ID = t1.SHIPVOYAGE_ID WHERE t.DEL_FLAG = 0 AND t.IS_PAYMENT = 1 GROUP BY t1.CUSTOMER_ID,t1.COMPANY_ID ) B ON A.CUSTOMER_ID = B.CUSTOMER_ID AND A.COMPANY_ID = B.COMPANY_ID LEFT JOIN ( select SUM( nvl(HAS_NOT_RECEIPT_AMOUNT,0)) INVOICE_AMOUNT,TFI.CUSTOMER_ID CUSTOMER_ID,TFI.COMPANY_ID from T_FD_INVOICE TFI where TFI.INVOICE_TYPE_CODE = '30' and status = '1' GROUP BY TFI.CUSTOMER_ID,TFI.COMPANY_ID ) C ON A.CUSTOMER_ID = C.CUSTOMER_ID AND A.COMPANY_ID = C.COMPANY_ID
A.CUSTOMER_ID = #{customerId}
AND A.COMPANY_ID = #{companyId}

SELECT tpwp.ID "planId",TBTC.TRUST_ID "trustId",TPWP.COMPANY_ID "companyId",TPWP.COMPANY_NAME "companyName"  FROM T_BUS_TRUST_CARGO tbtc
LEFT JOIN T_PRD_WORK_PLAN tpwp ON TBTC.TRUST_ID = TPWP.TRUST_ID
WHERE TBTC.id = #{trustCargoInfoId}
AND tpwp.PROCESS_CODE = #{processCd}
AND tpwp.WORK_DATE = #{workDate}
AND tpwp.CLASS_CODE = #{classCode}

SELECT
    tpwp.ID "planId",
    tpwp.TRUST_ID "trustId",
    tpwp.COMPANY_ID "companyId",
    tpwp.COMPANY_NAME "companyName"
FROM T_PRD_WORK_PLAN tpwp
WHERE tpwp.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId}
  AND tpwp.WORK_DATE = TO_DATE(#{workDate},'YYYY-MM-DD hh24:mi:ss')
  AND tpwp.CLASS_CODE = #{classCode}
  AND tpwp.PROCESS_CODE = #{processCd}
